sys_script_client.script:
// Copyrights belong to Discover Technologies LLC. © 2019 Discover Technologies LLC
// Script Continued Below
function onSubmit() {
	// STRY0076598
	if (g_form.getActionName() == 'Reopen') {
		if(g_form.getValue('active')!='false'){
			return false;
		}

		if(g_scratchpad.parent_sys_id + '' != '' && g_scratchpad.parent_active != 'true'){
			var link = "../discovertaskerportal?id=discovertasker_taskdetails&sys_id=" + g_scratchpad.parent_sys_id +"&table=x_153465_discovert_route_task_instance&view=sp&state=3&order=1";
			g_form.addErrorMessage(" <b>" + getMessage('Tasker - Reopen Parent is not active - start') + " " + '<a href='+link+'>' +g_scratchpad.parent_number+'</a>'  + ' ' + getMessage('Tasker - Reopen Parent is not active - end') + '</b>');
			return false;
		}

		// STRY0016025- RAJ 2019-04-20 - Determine if Tasker close date is beyond the allowable reopen days
		if (g_scratchpad.closed_to_long_to_reopen == 'true'){
			g_form.addErrorMessage(g_form.getValue('number') + ' ' + getMessage('Tasker - Closed too long to reopen 1') + ' ' + g_scratchpad.ReopenMaxDays + ' ' + getMessage('Tasker - Closed too long to reopen 2') + ' ' +  grTask.closed_at + getMessage('Tasker - Closed too long to reopen 3'));
			return false;
		}
		var bOpenSubtasks = false;
		// if here, then task can be reopened
		if(g_scratchpad.hasCanceledSubtask == 'true'){
			bOpenSubtasks = confirm(getMessage('Tasker - Do you want to reopen Subtasks'));
		}

		// reset ajax to call a different method
		var ajax = new GlideAjax('ClientTaskInfo');
		ajax.addParam('sysparm_name', 'reopenTask');
		ajax.addParam('sysparm_task', g_form.getUniqueValue());
		ajax.addParam('sysparm_reopenSubtasks', bOpenSubtasks);
//		ajax.getXML(function(response){
//			/* done, ignore the return */
//		});
		ajax.getXML(redirectPage);

	}
	function redirectPage(response) {
		var sysId = g_form.getUniqueValue();
		var url = '';
		if(typeof spModal != 'undefined')
			url = "../discovertaskerportal?id=discovertasker_taskdetails&sys_id=" + sysId +"&table=x_153465_discovert_route_task_instance&view=sp";
		else
			url = '/x_153465_discovert_route_task_instance.do?sys_id=' + sysId;	

		location.href=url;

	}

}
